<template>
  <div class="message-list-container">
    <el-card>
      <div class="filter-container">
        <el-form :inline="true" :model="listQuery" class="demo-form-inline">
          <el-form-item label="消息类型">
            <el-select v-model="listQuery.type" placeholder="全部类型" clearable>
              <el-option label="系统公告" value="system"></el-option>
              <el-option label="订单通知" value="order"></el-option>
              <el-option label="活动通知" value="activity"></el-option>
            </el-select>
          </el-form-item>
          <el-form-item label="目标用户">
            <el-select v-model="listQuery.targetType" placeholder="全部" clearable>
              <el-option label="全部用户" value="all"></el-option>
              <el-option label="指定用户" value="user"></el-option>
              <el-option label="管理员" value="admin"></el-option>
            </el-select>
          </el-form-item>
          <el-form-item label="状态">
            <el-select v-model="listQuery.status" placeholder="全部状态" clearable>
              <el-option label="草稿" value="0"></el-option>
              <el-option label="已发布" value="1"></el-option>
            </el-select>
          </el-form-item>
          <el-form-item label="时间范围">
            <el-date-picker
              v-model="dateRange"
              type="daterange"
              range-separator="至"
              start-placeholder="开始时间"
              end-placeholder="结束时间"
              value-format="yyyy-MM-dd"
              @change="handleDateChange"
            ></el-date-picker>
          </el-form-item>
          <el-form-item>
            <el-button type="primary" @click="handleSearch" icon="el-icon-search">查询</el-button>
            <el-button @click="resetQuery" icon="el-icon-refresh">重置</el-button>
          </el-form-item>
        </el-form>
      </div>

      <div class="action-container">
        <el-button type="primary" @click="handleAdd" icon="el-icon-plus">创建消息</el-button>
        <el-button type="success" @click="handleSendBatch" icon="el-icon-s-promotion">群发消息</el-button>
        <el-button type="warning" @click="handleMarkAllRead" icon="el-icon-check">全部已读</el-button>
        <el-button type="danger" @click="handleBatchDelete" :disabled="!selectedItems.length" icon="el-icon-delete">批量删除</el-button>
      </div>

      <el-table
        v-loading="listLoading"
        :data="list"
        border
        highlight-current-row
        @selection-change="handleSelectionChange"
      >
        <el-table-column type="selection" width="55"></el-table-column>
        <el-table-column prop="id" label="ID" width="80"></el-table-column>
        <el-table-column label="类型" width="100">
          <template slot-scope="scope">
            <el-tag :type="getTypeTagType(scope.row.type)">{{ getTypeText(scope.row.type) }}</el-tag>
          </template>
        </el-table-column>
        <el-table-column prop="title" label="标题" min-width="150"></el-table-column>
        <el-table-column prop="content" label="内容摘要" min-width="200" show-overflow-tooltip></el-table-column>
        <el-table-column label="目标" width="100">
          <template slot-scope="scope">
            <el-tag type="info">{{ getTargetText(scope.row.targetType) }}</el-tag>
          </template>
        </el-table-column>
        <el-table-column prop="readCount" label="阅读数" width="100"></el-table-column>
        <el-table-column label="状态" width="100">
          <template slot-scope="scope">
            <el-tag :type="scope.row.status === 1 ? 'success' : 'info'">{{ scope.row.status === 1 ? '已发布' : '草稿' }}</el-tag>
          </template>
        </el-table-column>
        <el-table-column prop="createTime" label="创建时间" width="180"></el-table-column>
        <el-table-column label="操作" width="200" fixed="right">
          <template slot-scope="scope">
            <el-button size="mini" @click="handleView(scope.row)">详情</el-button>
            <el-button size="mini" type="primary" @click="handleEdit(scope.row)">编辑</el-button>
            <el-button size="mini" type="danger" @click="handleDelete(scope.row)">删除</el-button>
          </template>
        </el-table-column>
      </el-table>
      <el-empty v-if="!listLoading && list.length === 0" description="暂无数据" />

      <div class="pagination-container">
        <el-pagination
          background
          @size-change="handleSizeChange"
          @current-change="handleCurrentChange"
          :current-page="listQuery.page"
          :page-sizes="[10, 20, 30, 50]"
          :page-size="listQuery.pageSize"
          layout="total, sizes, prev, pager, next, jumper"
          :total="total"
        ></el-pagination>
      </div>
    </el-card>

    <el-dialog :title="dialogStatus === 'create' ? '创建消息' : '编辑消息'" :visible.sync="dialogVisible" width="600px">
      <el-form :model="form" :rules="rules" ref="messageForm" label-width="100px">
        <el-form-item label="消息类型" prop="type">
          <el-select v-model="form.type" placeholder="请选择类型">
            <el-option label="系统公告" value="system"></el-option>
            <el-option label="订单通知" value="order"></el-option>
            <el-option label="活动通知" value="activity"></el-option>
          </el-select>
        </el-form-item>
        <el-form-item label="消息标题" prop="title">
          <el-input v-model="form.title" placeholder="请输入消息标题" maxlength="50" show-word-limit></el-input>
        </el-form-item>
        <el-form-item label="消息内容" prop="content">
          <el-input type="textarea" v-model="form.content" :rows="5" placeholder="请输入消息内容" maxlength="500" show-word-limit></el-input>
        </el-form-item>
        <el-form-item label="目标用户" prop="targetType">
          <el-select v-model="form.targetType" placeholder="请选择">
            <el-option label="全部用户" value="all"></el-option>
            <el-option label="指定用户" value="user"></el-option>
            <el-option label="管理员" value="admin"></el-option>
          </el-select>
        </el-form-item>
        <el-form-item label="发布状态">
          <el-switch v-model="form.status" :active-value="1" :inactive-value="0"></el-switch>
          <span class="form-tip" style="margin-left: 10px">{{ form.status === 1 ? '立即发布' : '存为草稿' }}</span>
        </el-form-item>
      </el-form>
      <div slot="footer" class="dialog-footer">
        <el-button @click="dialogVisible = false">取消</el-button>
        <el-button @click="handleSaveDraft" :loading="submitLoading">保存草稿</el-button>
        <el-button type="primary" @click="handlePublish" :loading="submitLoading">发布</el-button>
      </div>
    </el-dialog>

    <el-dialog title="消息详情" :visible.sync="detailVisible" width="600px">
      <el-form :model="detail" label-width="100px">
        <el-form-item label="消息类型">
          <el-tag :type="getTypeTagType(detail.type)">{{ getTypeText(detail.type) }}</el-tag>
        </el-form-item>
        <el-form-item label="消息标题">
          <span>{{ detail.title }}</span>
        </el-form-item>
        <el-form-item label="消息内容">
          <div class="content-box">{{ detail.content }}</div>
        </el-form-item>
        <el-form-item label="目标用户">
          <el-tag type="info">{{ getTargetText(detail.targetType) }}</el-tag>
        </el-form-item>
        <el-form-item label="阅读数">
          <span>{{ detail.readCount }} 次</span>
        </el-form-item>
        <el-form-item label="状态">
          <el-tag :type="detail.status === 1 ? 'success' : 'info'">{{ detail.status === 1 ? '已发布' : '草稿' }}</el-tag>
        </el-form-item>
        <el-form-item label="创建时间">
          <span>{{ detail.createTime }}</span>
        </el-form-item>
      </el-form>
      <div slot="footer" class="dialog-footer">
        <el-button @click="detailVisible = false">关闭</el-button>
      </div>
    </el-dialog>

    <el-dialog title="群发消息" :visible.sync="sendDialogVisible" width="500px">
      <el-form :model="sendForm" :rules="sendRules" ref="sendForm" label-width="100px">
        <el-form-item label="消息类型" prop="type">
          <el-select v-model="sendForm.type" placeholder="请选择">
            <el-option label="系统公告" value="system"></el-option>
            <el-option label="活动通知" value="activity"></el-option>
          </el-select>
        </el-form-item>
        <el-form-item label="消息标题" prop="title">
          <el-input v-model="sendForm.title" placeholder="请输入"></el-input>
        </el-form-item>
        <el-form-item label="消息内容" prop="content">
          <el-input type="textarea" v-model="sendForm.content" :rows="4" placeholder="请输入"></el-input>
        </el-form-item>
        <el-form-item label="发送范围">
          <el-radio-group v-model="sendForm.targetType">
            <el-radio label="all">全部用户</el-radio>
            <el-radio label="user">指定用户</el-radio>
          </el-radio-group>
        </el-form-item>
        <el-form-item label="用户ID" v-if="sendForm.targetType === 'user'" prop="userIds">
          <el-input v-model="sendForm.userIds" placeholder="多个用逗号分隔" type="textarea" :rows="2"></el-input>
        </el-form-item>
      </el-form>
      <div slot="footer" class="dialog-footer">
        <el-button @click="sendDialogVisible = false">取消</el-button>
        <el-button type="primary" @click="confirmSend" :loading="sendLoading">确认发送</el-button>
      </div>
    </el-dialog>
  </div>
</template>

<script>
import request from '@/api'

export default {
  name: 'MessageList',
  data() {
    return {
      list: [],
      total: 0,
      listLoading: true,
      listQuery: {
        page: 1,
        pageSize: 10,
        type: '',
        targetType: '',
        status: ''
      },
      dateRange: [],
      selectedItems: [],
      dialogVisible: false,
      dialogStatus: 'create',
      submitLoading: false,
      detailVisible: false,
      sendDialogVisible: false,
      sendLoading: false,
      detail: {},
      form: {
        type: 'system',
        title: '',
        content: '',
        targetType: 'all',
        status: 0
      },
      sendForm: {
        type: 'system',
        title: '',
        content: '',
        targetType: 'all',
        userIds: ''
      },
      rules: {
        type: [{ required: true, message: '请选择消息类型', trigger: 'change' }],
        title: [{ required: true, message: '请输入标题', trigger: 'blur' }],
        content: [{ required: true, message: '请输入内容', trigger: 'blur' }],
        targetType: [{ required: true, message: '请选择目标用户', trigger: 'change' }]
      },
      sendRules: {
        type: [{ required: true, message: '请选择消息类型', trigger: 'change' }],
        title: [{ required: true, message: '请输入标题', trigger: 'blur' }],
        content: [{ required: true, message: '请输入内容', trigger: 'blur' }]
      }
    }
  },
  created() {
    this.fetchData()
  },
  methods: {
    fetchData() {
      this.listLoading = true
      const params = {
        ...this.listQuery
      }
      if (this.dateRange && this.dateRange.length === 2) {
        params.startDate = this.dateRange[0]
        params.endDate = this.dateRange[1]
      }
      request({
        url: '/api/admin/messages',
        method: 'get',
        params
      }).then(res => {
        if (res.code === 0) {
          this.list = res.data.list || []
          this.total = res.data.total || 0
        }
        this.listLoading = false
      }).catch(() => {
        this.listLoading = false
      })
    },
    handleSearch() {
      this.listQuery.page = 1
      this.fetchData()
    },
    resetQuery() {
      this.listQuery = {
        page: 1,
        pageSize: 10,
        type: '',
        targetType: '',
        status: ''
      }
      this.dateRange = []
      this.fetchData()
    },
    handleDateChange() {},
    handleSizeChange(val) {
      this.listQuery.pageSize = val
      this.fetchData()
    },
    handleCurrentChange(val) {
      this.listQuery.page = val
      this.fetchData()
    },
    handleSelectionChange(val) {
      this.selectedItems = val
    },
    handleAdd() {
      this.dialogStatus = 'create'
      this.form = {
        type: 'system',
        title: '',
        content: '',
        targetType: 'all',
        status: 0
      }
      this.dialogVisible = true
    },
    handleView(row) {
      this.detail = { ...row }
      this.detailVisible = true
    },
    handleEdit(row) {
      this.dialogStatus = 'update'
      this.form = { ...row }
      this.dialogVisible = true
    },
    handleDelete(row) {
      this.$confirm('确定要删除这条消息吗？', '提示', {
        confirmButtonText: '确定',
        cancelButtonText: '取消',
        type: 'warning'
      }).then(() => {
        request({
          url: `/api/admin/messages/${row.id}`,
          method: 'delete'
        }).then(res => {
          if (res.code === 0) {
            this.$message.success('删除成功')
            this.fetchData()
          }
        })
      })
    },
    handleSaveDraft() {
      this.form.status = 0
      this.submitForm()
    },
    handlePublish() {
      this.form.status = 1
      this.submitForm()
    },
    submitForm() {
      this.$refs.messageForm.validate(valid => {
        if (valid) {
          this.submitLoading = true
          const method = this.dialogStatus === 'create' ? 'post' : 'put'
          const url = this.dialogStatus === 'create'
            ? '/api/admin/messages'
            : `/api/admin/messages/${this.form.id}`
          request({
            url,
            method,
            data: this.form
          }).then(res => {
            if (res.code === 0) {
              this.$message.success(this.dialogStatus === 'create' ? '创建成功' : '更新成功')
              this.dialogVisible = false
              this.fetchData()
            }
            this.submitLoading = false
          }).catch(() => {
            this.submitLoading = false
          })
        }
      })
    },
    handleSendBatch() {
      this.sendForm = {
        type: 'system',
        title: '',
        content: '',
        targetType: 'all',
        userIds: ''
      }
      this.sendDialogVisible = true
    },
    confirmSend() {
      this.$refs.sendForm.validate(valid => {
        if (valid) {
          this.sendLoading = true
          request({
            url: '/api/admin/messages/send',
            method: 'post',
            data: this.sendForm
          }).then(res => {
            if (res.code === 0) {
              this.$message.success(`发送成功，已发送给 ${res.data.sentCount} 人`)
              this.sendDialogVisible = false
              this.fetchData()
            }
            this.sendLoading = false
          }).catch(() => {
            this.sendLoading = false
          })
        }
      })
    },
    handleMarkAllRead() {
      request({
        url: '/api/admin/messages/mark-read',
        method: 'put',
        data: { ids: [] }
      }).then(res => {
        if (res.code === 0) {
          this.$message.success('已将所有消息标记为已读')
          this.fetchData()
        }
      })
    },
    handleBatchDelete() {
      if (this.selectedItems.length === 0) {
        this.$message.warning('请选择要删除的消息')
        return
      }
      this.$confirm(`确定要删除选中的 ${this.selectedItems.length} 条消息吗？`, '提示', {
        confirmButtonText: '确定',
        cancelButtonText: '取消',
        type: 'warning'
      }).then(() => {
        const ids = this.selectedItems.map(item => item.id)
        request({
          url: '/api/admin/messages/batch',
          method: 'delete',
          data: { ids }
        }).then(res => {
          if (res.code === 0) {
            this.$message.success(`成功删除 ${ids.length} 条消息`)
            this.selectedItems = []
            this.fetchData()
          }
        }).catch(() => {
          this.$message.error('删除失败')
        })
      })
    },
    getTypeTagType(type) {
      const types = {
        'system': 'primary',
        'order': 'success',
        'activity': 'warning'
      }
      return types[type] || 'info'
    },
    getTypeText(type) {
      const texts = {
        'system': '系统公告',
        'order': '订单通知',
        'activity': '活动通知'
      }
      return texts[type] || type
    },
    getTargetText(targetType) {
      const texts = {
        'all': '全部用户',
        'user': '指定用户',
        'admin': '管理员'
      }
      return texts[targetType] || targetType
    }
  }
}
</script>

<style lang="scss" scoped>
.message-list-container {
  padding: 20px;
}

.filter-container {
  margin-bottom: 20px;
}

.action-container {
  margin-bottom: 20px;
}

.pagination-container {
  margin-top: 20px;
  text-align: right;
}

.form-tip {
  color: #909399;
  font-size: 12px;
  margin-left: 10px;
}

.content-box {
  padding: 10px;
  background: #f5f7fa;
  border-radius: 4px;
  line-height: 1.6;
}
</style>
